    if (notificationId) await Notifications.cancelNotificationAsync(notificationId);
    try {
      const result = await Notifications.scheduleNotificationAsync({
        content: 'You pressed the button',
        title: 'Local Alert',
        body: 'This is a local push notification',
        id: `local-${Date.now()}`,
      });
      setNotificationId(result.id);
