import { SQLite, Database } from 'expo-sqlite';

const db = new SQLite('todos.db');

function App() {
  const [todos, setTodos] = useState<Array<{ id: number; text: string }>>([]);
  const [newTodo, setNewTodo] = useState<string>('');

  // Initialize DB and create table
  useEffect(() => {
    db.transaction(
      (tx) =>
        tx.executeSql(
          'CREATE TABLE IF NOT EXISTS todos (id INTEGER PRIMARY KEY AUTOINCREMENT, text TEXT)',
          [],
          () => {},
          (err) => console.error(err)
        ),
      (err) => console.error(err),
    );
  }, []);

  // Load todos
  useEffect(() => {
    db.transaction(
      (tx) =>
        tx.executeSql('SELECT * FROM todos ORDER BY id DESC', [], (_, res) => {
          const rows = [];
          for (let i = 0; i < res.rows.length; i++) {
            rows.push({ id: res.rows[i].id, text: res.rows[i].text });
          }
          setTodos(rows);
        }),
      (err) => console.error(err),
    );
  }, []);

  // Add todo
  const addTodo = async () => {
    if (!newTodo.trim()) return;
    await db.transaction(
      (tx) =>
        tx.executeSql('INSERT INTO todos (text) VALUES (?)', [newTodo], (_, res) => {}),
      (err) => console.error(err)
    );
    setTodos((prev) => [...prev, { id: Date.now(), text: newTodo }]);
    setNewTodo('');
  };

  // Delete todo
  const deleteTodo = async (id: number) => {
    await db.transaction(
      (tx) =>
        tx.executeSql('DELETE FROM todos WHERE id = ?', [id], (_, res) => {}),
      (err) => console.error(err)
    );
    setTodos((prev) => prev.filter((t) => t.id !== id));
  };

  return (
    <View style={styles.container}>
      <Input
        value={newTodo}
        onChangeText={(text) => setNewTodo(text)}
        placeholder="Add a todo"
        style={styles.input}
      />
      <Button title="Add" onPress={addTodo} disabled={!newTodo.trim() || todos.length === 0} />
      {todos.length > 0 && (
        <View style={styles.list}>
          {todos.map((todo) => (
            <View key={todo.id} style={styles.item}>
              <Text>{todo.text}</Text>
              <Button
                title="Delete"
                onPress={() => deleteTodo(todo.id)}
                color="#ff4d4f"
                disabled={!todo}
              />
            </View>
          ))}
        </View>
      )}
    </View>
  );
}

export default App;

