import React, {useRef} from 'react';
import {View, Text, StyleSheet} from 'react-native';
import {PanGestureHandler, PanGestureEvent} from '@react-native-gesture-handler/gesture-handlers';
import Animated, {
  useSharedValue,
  runOnUI,
  useAnimatedGestureHandler
} from '@react-native-reanimated';

type DraggableBoxProps = {};

export default function DraggableBox() {
  const x = useSharedValue(0);
  const y = useSharedValue(0);

  const gestureRef = useRef<PanGestureHandler>(null!);

  const onGestureEvent = useAnimatedGestureHandler({
    onStart: (_, ctx) => {
      gestureRef.current?.onStart(ctx);
    },
    onActive: (event, ctx) => {
      x.value = event.translationX;
      y.value = event.translationY;
    },
    onEnd: () => {
      runOnUI(() => {
        x.value = 0;
        y.value = 0;
      });
    }
  });

  return (
    <PanGestureHandler gestureRef={gestureRef} onGestureEvent={onGestureEvent}>
      <Animated.View style={{transform: [{x, y}]}} />
    </PanGestureHandler>
  );
}

