    opacity: isSwipedUp ? 0.5 : 1,
  }));

  return (
    <GestureHandlerRootView>
      {['Card1', 'Card2'].map((id) => {
        const title = `Title ${id}`;
        const isSwiped = React.useMemo(() => id === 'Card1' && isSwipedUp, [isSwipedUp]);

        return (
          <PanGestureHandler
            onGestureEvent={e => {
              if (e.state.isActive) return;
              const distance = e.translationX;
              setIsSwipedUp(distance > 10 && id === 'Card1');
            }}
          >
            <Animated.View style={[styles.card, cardStyle]}>
              <View style={styles.content}>
                <Text>{title}</Text>
              </View>
            </Animated.View>
          </PanGestureHandler>
        );
      })}
    </GestureHandlerRootView>
  );
}

