import React, { useState } from 'react';
import {
  View,
  TextInput,
  Text,
  StyleSheet,
  Alert,
  Button,
} from 'react-native';

const LoginForm = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [emailError, setEmailError] = useState<string | null>(null);
  const [passwordError, setPasswordError] = useState<string | null>(null);

  const validateEmail = (value: string) => {
    if (!value) return 'Email is required';
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return !emailRegex.test(value) ? 'Invalid email format' : null;
  };

  const validatePassword = (value: string) => {
    if (!value) return 'Password is required';
    return value.length < 6 ? 'Password must be at least 6 characters' : null;
  };

  const handleSubmit = () => {
    setEmailError(validateEmail(email));
    setPasswordError(validatePassword(password));

    if (emailError === null && passwordError === null) {
      Alert.alert('Login successful', 'Welcome!');
    }
  };

  return (
    <View style={styles.container}>
      <TextInput
        style={styles.input}
        placeholder="Email"
        value={email}
        onChangeText={setEmail}
        errorMessage={emailError ? emailError : null}
        keyboardType="email-address"
      />
      {emailError && <Text style={styles.error}>{emailError}</Text>}

      <TextInput
        style={styles.input}
        placeholder="Password"
        value={password}
        onChangeText={setPassword}
        errorMessage={passwordError ? passwordError : null}
        secureTextEntry
      />
      {passwordError && <Text style={styles.error}>{passwordError}</Text>}

      <Button title="Login" onPress={handleSubmit} disabled={emailError || passwordError} />
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    justifyContent: 'center',
    paddingHorizontal: 20,
  },
  input: {
    borderWidth: 1,
    borderColor: '#ccc',
    borderRadius: 5,
    padding: 10,
    marginBottom: 10,
  },
  error: {
    color: 'red',
    fontSize: 14,
    textAlign: 'center',
  },
});

export default LoginForm;

import React, { useState } from 'react';
import { View, Text, ActivityIndicator, StyleSheet } from 'react-native';

type Data1 = any[];
type Data2 = any[];

const MyComponent: React.FC = () => {
  const [data1, setData1] = useState<Data1>([]);
  const [data2, setData2] = useState<Data2>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    async function fetchBoth() {
      try {
        const response1 = await fetch('https://api.example.com/data1');
        const data1Res = await response1.json();
        const response2 = await fetch('https://api.example.com/data2');
        const data2Res = await response2.json();

        Promise.all([data1Res, data2Res])
          .then(([res1, res2]) => {
            setData1(res1);
            setData2(res2);
          })
          .catch(err => console.error(err));
      } catch (err) {
        setError('Failed to fetch data');
      } finally {
        setLoading(false);
      }
    }

    fetchBoth();
  }, []);

  if (loading) return <ActivityIndicator size="large" />;
  if (error) return <Text>Error: {error}</Text>;

  return (
    <View style={styles.container}>
      <Text>Data1:</Text>
      <Text>{JSON.stringify(data1)}</Text>

      <Text>Data2:</Text>
      <Text>{JSON.stringify(data2)}</Text>
    </View>
  );
};

const styles = StyleSheet.create({
  container: { padding: 20 },
});

export default MyComponent;

import React, { useState, useEffect } from 'react';
import { View, Text, Button, StyleSheet } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';

export default function App() {
  const [theme, setTheme] = useState<string>('light');

  useEffect(() => {
    AsyncStorage.getItem('theme')
      .then((value) => {
        if (value === 'dark') setTheme('dark');
      });
  }, []);

  const toggleTheme = async () => {
    const newTheme = theme === 'light' ? 'dark' : 'light';
    await AsyncStorage.setItem('theme', newTheme);
    setTheme(newTheme);
  };

  return (
    <View style={styles.container}>
      <Text>Current: {theme}</Text>
      <Button title="Toggle" onPress={toggleTheme} />
    </View>
  );

  const styles = StyleSheet.create({
    container: {
      flex: 1,
      justifyContent: 'center',
      alignItems: 'center',
    },
  });
}

