import React from 'react';
import { FlatList, View } from 'react-native';

const Item = React.memo(({ index }) => (
  <View style={{ height: 44 }} />
));

export default function LargeFlatList() {
  const dataLength = 10_000;
  const items = Array.from({ length: dataLength }, (_, i) => ({
    id: i,
    text: `Item ${i}`,
  }));

  const getItemLayout = (index, style) => ({
    length: 44,
    offset: index * 44,
    index,
  });

  const windowSize = Math.ceil(dataLength / 25);

  return (
    <FlatList
      data={items}
      keyExtractor={(item) => item.id.toString()}
      renderItem={React.memo(Item)}
      getItemLayout={getItemLayout}
      windowSize={windowSize}
      contentContainerStyle={{ paddingBottom: 10 }}
    />
  );
}

